function extractLeads(serpApiResponse, batchMeta) {
  const {
    search_metadata,
    search_parameters,
    local_results = []
  } = serpApiResponse;

  return local_results.map(item => ({
    // id: "new",
    batch_id: batchMeta.batch_id,              // e.g. AUSTIN_TX_RE_2025_WK3
    search_id: search_metadata.id,
    keyword: search_parameters.q,
    city: batchMeta.city,
    state: batchMeta.state,
    country: batchMeta.country,

    title: item.title || null,
    place_id: item.place_id,                   // UNIQUE KEY
    data_cid: item.data_cid || null,

    rating: item.rating || null,
    reviews: item.reviews || 0,

    phone: item.phone || null,
    website: item.website || null,
    address: item.address || null,

    latitude: item.gps_coordinates?.latitude || null,
    longitude: item.gps_coordinates?.longitude || null,

    categories: item.types || [],
    is_open: item.open_state?.toLowerCase().includes("open") || false,

    scraped_at: new Date().toISOString()
  }));
}
// Loop over input items and add a new field called 'myNewField' to the JSON of each one
let response = [];
for (const item of $input.all()) {
  const batchMeta = {
    source : 'google',
    batch_id: item.json.id,
    city: item.json.city,
    state: item.json.state,
    country: item.json.country
  };
  const leads = extractLeads(item.json, batchMeta);
  response.push(...leads);
}

return response;

function tagLeadByScore(score) {
  if (score >= 80) {
    return {
      lead_tag: "HOT",
      lead_stage: "Direct Outreach",
      priority: 1
    };
  }

  if (score >= 40) {
    return {
      lead_tag: "WARM",
      lead_stage: "Email + LinkedIn",
      priority: 2
    };
  }

  if (score >= 20) {
    return {
      lead_tag: "COLD",
      lead_stage: "Nurture",
      priority: 3
    };
  }

  return {
    lead_tag: "LOW",
    lead_stage: "Skip",
    priority: 4
  };
}

function calculateLeadScore(lead) {
  const rating = lead.rating || 1;
  const reviews = lead.reviews || 0;

  const ratingScore = rating;
  const reviewScore = Math.log10(reviews + 1) * 10;
  const websiteMultiplier = lead.website ? 1.3 : 0.7;

  const score = ratingScore * reviewScore * websiteMultiplier;

  return Math.round(score);
}
// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.lead_score  = calculateLeadScore(item.json);
  const score = Number(item.json.lead_score) || 0;
  const tags = tagLeadByScore(score);
  item.json.lead_tag = tags.lead_tag;
  item.json.lead_stage = tags.lead_stage;
  item.json.priority = tags.priority;
}

return $input.all();

